const PROCESSING_FEE = 5;

const BASE_PREMIUMS: Record<string, number> = {
  sword: 100,
  amulet: 60,
};

export const runScenario = (scenario: any): unknown => {
  const items = scenario?.steps?.[0]?.items ?? [];
  let premium = PROCESSING_FEE;
  if (items.length > 0) {
    const base = items.reduce((sum: number, item: any) => sum + (BASE_PREMIUMS[item.type] ?? 0), 0);
    premium = base * 1.1 + PROCESSING_FEE;
  }
  return { results: [{ premium }] };
};

